import { useState } from "react";
import {
  LineChart, Line, BarChart, Bar, AreaChart, Area,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from "recharts";

// ─── Default seller ───────────────────────────────────────────────────────────
const DEFAULT_SELLER = {
  name: 'Rajan Kumar',
  email: 'rajan@agri.com',
  phone: '+91 98765 43210',
  location: 'Nashik, Maharashtra',
  aadhar: '1234 5678 9012',
  pan: 'ABCDE1234F',
  joined: 'January 2025',
};

// ─── Static chart data ────────────────────────────────────────────────────────
const earningsData = [
  { month: 'Aug', earnings: 12400, profit: 4200 },
  { month: 'Sep', earnings: 18700, profit: 6800 },
  { month: 'Oct', earnings: 15300, profit: 5100 },
  { month: 'Nov', earnings: 22100, profit: 8900 },
  { month: 'Dec', earnings: 19800, profit: 7300 },
  { month: 'Jan', earnings: 27500, profit: 11200 },
  { month: 'Feb', earnings: 31200, profit: 13400 },
];

const growthData = [
  { week: 'W1', orders: 8,  revenue: 4200  },
  { week: 'W2', orders: 14, revenue: 7800  },
  { week: 'W3', orders: 11, revenue: 5900  },
  { week: 'W4', orders: 19, revenue: 10300 },
  { week: 'W5', orders: 23, revenue: 12700 },
  { week: 'W6', orders: 17, revenue: 9100  },
  { week: 'W7', orders: 28, revenue: 15600 },
  { week: 'W8', orders: 31, revenue: 18200 },
];

const SEED_PRODUCTS = [
  { id: 1, title: 'Organic Tomatoes',  desc: 'Fresh, pesticide-free tomatoes from my farm.', image: 'https://images.unsplash.com/photo-1540148426945-6cf22a6b2383?w=300&q=80', location: 'Nashik, MH',    price: 45,  category: 'Vegetables', stock: 200, status: 'active' },
  { id: 2, title: 'Alphonso Mangoes',  desc: 'Premium Alphonso mangoes, export quality.',     image: 'https://images.unsplash.com/photo-1574316071802-0d684efa7bf5?w=300&q=80', location: 'Ratnagiri, MH', price: 320, category: 'Fruits',     stock: 80,  status: 'active' },
  { id: 3, title: 'Basmati Rice',      desc: 'Long-grain aromatic basmati, 1 year aged.',     image: 'https://images.unsplash.com/photo-1586201375761-83865001e31c?w=300&q=80', location: 'Nashik, MH',    price: 95,  category: 'Grains',     stock: 500, status: 'inactive' },
];

const BANK_DEFAULT = { accountName: '', accountNumber: '', ifsc: '', bankName: '', upiId: '' };

const navItems = [
  { id: 'dashboard', icon: '▦',  label: 'Dashboard'    },
  { id: 'products',  icon: '🌿', label: 'My Products'  },
  { id: 'bank',      icon: '🏦', label: 'Bank Details' },
  { id: 'profile',   icon: '👤', label: 'My Profile'   },
];

export default function SellerDash() {
  const seller = DEFAULT_SELLER;
  const avatarInitials = seller.name
    ? seller.name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2)
    : 'S';

  const [activeTab, setActiveTab]       = useState('dashboard');
  const [products, setProducts]         = useState(SEED_PRODUCTS);
  const [bankDetails, setBankDetails]   = useState(BANK_DEFAULT);
  const [showAddModal, setShowAddModal] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [bankSaved, setBankSaved]       = useState(false);
  const [addError, setAddError]         = useState('');
  const [editProduct, setEditProduct]   = useState(null);
  const [newProduct, setNewProduct]     = useState({
    title: '', desc: '', image: '', location: '', price: '', category: 'Vegetables', stock: ''
  });

  const handleAddProduct = () => {
    if (!newProduct.title.trim() || !newProduct.price || !newProduct.location.trim()) {
      setAddError('Title, price and location are required.');
      return;
    }
    const product = {
      ...newProduct,
      id:     Date.now(),
      price:  parseFloat(newProduct.price) || 0,
      stock:  parseInt(newProduct.stock)   || 0,
      status: 'active',
    };
    setProducts(prev => [product, ...prev]);
    setNewProduct({ title: '', desc: '', image: '', location: '', price: '', category: 'Vegetables', stock: '' });
    setAddError('');
    setShowAddModal(false);
  };

  const handleUpdateProduct = () => {
    if (!editProduct.title.trim() || !editProduct.price || !editProduct.location.trim()) return;
    setProducts(prev => prev.map(p => p.id === editProduct.id
      ? { ...editProduct, price: parseFloat(editProduct.price), stock: parseInt(editProduct.stock) || 0 }
      : p
    ));
    setEditProduct(null);
  };

  const handleDeleteProduct = (id) => {
    setProducts(prev => prev.filter(p => p.id !== id));
    setDeleteConfirm(null);
  };

  const toggleStatus = (id) => {
    setProducts(prev => prev.map(p =>
      p.id === id ? { ...p, status: p.status === 'active' ? 'inactive' : 'active' } : p
    ));
  };

  const handleSaveBank = () => {
    setBankSaved(true);
    setTimeout(() => setBankSaved(false), 3000);
  };

  const totalEarnings  = earningsData.reduce((s, d) => s + d.earnings, 0);
  const totalProfit    = earningsData.reduce((s, d) => s + d.profit,   0);
  const activeProducts = products.filter(p => p.status === 'active').length;

  const inputStyle = {
    border: '1.5px solid #e5e7eb', borderRadius: 12,
    padding: '11px 14px', fontSize: 14, color: '#111827',
    outline: 'none', fontFamily: 'inherit', width: '100%',
    boxSizing: 'border-box', background: '#fafafa',
  };

  const fieldBlock = (label, key, type = 'text', placeholder = '', stateObj, setFn, isTextarea = false) => (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
      <label style={S.formLabel}>{label}</label>
      {isTextarea
        ? <textarea placeholder={placeholder} value={stateObj[key]}
            onChange={e => setFn(p => ({ ...p, [key]: e.target.value }))}
            style={{ ...inputStyle, height: 72, resize: 'vertical' }} />
        : <input type={type} placeholder={placeholder} value={stateObj[key]}
            onChange={e => setFn(p => ({ ...p, [key]: e.target.value }))}
            style={inputStyle} />
      }
    </div>
  );

  return (
    <div style={S.root}>

      {/* ══════════ SIDEBAR ══════════ */}
      <aside style={S.sidebar}>
        <div style={S.sidebarLogo}>
          <span style={S.logoText}>AGRI<span style={S.logoAccent}>-AI</span></span>
          <span style={S.logoSub}>Seller Portal</span>
        </div>

        <div style={S.sidebarAvatar}>
          <div style={S.avatarCircle}>{avatarInitials}</div>
          <div>
            <div style={S.avatarName}>{seller.name}</div>
            <div style={S.avatarRole}>✅ Verified Seller</div>
          </div>
        </div>

        <nav style={S.sidebarNav}>
          {navItems.map(item => (
            <button key={item.id}
              style={{ ...S.navItem, ...(activeTab === item.id ? S.navItemActive : {}) }}
              onClick={() => setActiveTab(item.id)}>
              <span style={S.navIcon}>{item.icon}</span>
              {item.label}
              {item.id === 'products' && (
                <span style={S.navBadge}>{products.length}</span>
              )}
            </button>
          ))}
        </nav>

        <div style={S.sidebarFooter}>
          <div style={S.sidebarBadge}>🌱 Eco Certified</div>
          <div style={S.sidebarJoined}>Member since {seller.joined}</div>
        </div>
      </aside>

      {/* ══════════ MAIN ══════════ */}
      <main style={S.main}>
        <header style={S.topbar}>
          <div>
            <div style={S.topbarTitle}>
              {navItems.find(n => n.id === activeTab)?.label}
            </div>
            <div style={S.topbarSub}>
              Welcome back, {seller.name.split(' ')[0]}! Here's your farm activity today.
            </div>
          </div>
          <div style={S.topbarRight}>
            <div style={S.topbarDate}>
              {new Date().toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long' })}
            </div>
            <div style={S.topbarAvatar}>{avatarInitials}</div>
          </div>
        </header>

        <div style={S.content}>

          {/* ════ DASHBOARD ════ */}
          {activeTab === 'dashboard' && (
            <>
              <div style={S.statsGrid}>
                {[
                  { label: 'Total Earnings',   value: `₹${(totalEarnings/1000).toFixed(1)}K`, change: '+18.4% this month', color: '#22c55e', bg: '#f0fdf4' },
                  { label: 'Net Profit',        value: `₹${(totalProfit/1000).toFixed(1)}K`,   change: '+12.7% this month', color: '#3b82f6', bg: '#eff6ff' },
                  { label: 'Active Listings',   value: activeProducts,                          change: `${products.length} total listings`, color: '#f59e0b', bg: '#fffbeb' },
                  { label: 'Monthly Growth',    value: '31.2%',                                 change: '+8.3% vs last month', color: '#8b5cf6', bg: '#f5f3ff' },
                ].map((s, i) => (
                  <div key={i} style={{ ...S.statCard, background: s.bg, borderLeft: `4px solid ${s.color}` }}>
                    <div style={S.statLabel}>{s.label}</div>
                    <div style={{ ...S.statValue, color: s.color }}>{s.value}</div>
                    <div style={S.statChange}>{s.change}</div>
                  </div>
                ))}
              </div>

              <div style={S.chartsRow}>
                <div style={S.chartCard}>
                  <div style={S.chartTitle}>Earnings & Profit</div>
                  <div style={S.chartSub}>Last 7 months performance</div>
                  <ResponsiveContainer width="100%" height={210}>
                    <LineChart data={earningsData}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                      <XAxis dataKey="month" tick={{ fontSize: 11, fill: '#888' }} />
                      <YAxis tick={{ fontSize: 11, fill: '#888' }} tickFormatter={v => `₹${(v/1000).toFixed(0)}K`} />
                      <Tooltip formatter={(v, n) => [`₹${v.toLocaleString()}`, n === 'earnings' ? 'Earnings' : 'Profit']} />
                      <Legend />
                      <Line type="monotone" dataKey="earnings" stroke="#22c55e" strokeWidth={2.5} dot={{ r: 4 }} activeDot={{ r: 6 }} />
                      <Line type="monotone" dataKey="profit"   stroke="#3b82f6" strokeWidth={2.5} dot={{ r: 4 }} activeDot={{ r: 6 }} />
                    </LineChart>
                  </ResponsiveContainer>
                </div>

                <div style={S.chartCard}>
                  <div style={S.chartTitle}>Weekly Growth</div>
                  <div style={S.chartSub}>Orders & Revenue trend</div>
                  <ResponsiveContainer width="100%" height={210}>
                    <AreaChart data={growthData}>
                      <defs>
                        <linearGradient id="revGrad" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%"  stopColor="#22c55e" stopOpacity={0.25} />
                          <stop offset="95%" stopColor="#22c55e" stopOpacity={0} />
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                      <XAxis dataKey="week" tick={{ fontSize: 11, fill: '#888' }} />
                      <YAxis tick={{ fontSize: 11, fill: '#888' }} />
                      <Tooltip />
                      <Legend />
                      <Area  type="monotone" dataKey="revenue" stroke="#22c55e" fill="url(#revGrad)" strokeWidth={2.5} name="Revenue" />
                      <Line  type="monotone" dataKey="orders"  stroke="#f59e0b" strokeWidth={2} dot={false} name="Orders" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <div style={S.chartCard}>
                <div style={S.chartTitle}>Monthly Profit Breakdown</div>
                <div style={S.chartSub}>Earnings vs profit retained after costs</div>
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={earningsData} barSize={32}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" vertical={false} />
                    <XAxis dataKey="month" tick={{ fontSize: 11, fill: '#888' }} />
                    <YAxis tick={{ fontSize: 11, fill: '#888' }} tickFormatter={v => `₹${(v/1000).toFixed(0)}K`} />
                    <Tooltip formatter={v => `₹${v.toLocaleString()}`} />
                    <Bar dataKey="earnings" fill="#bbf7d0" radius={[6,6,0,0]} name="Earnings" />
                    <Bar dataKey="profit"   fill="#22c55e" radius={[6,6,0,0]} name="Profit"   />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </>
          )}

          {/* ════ MY PRODUCTS ════ */}
          {activeTab === 'products' && (
            <>
              <div style={S.productsHeader}>
                <div>
                  <div style={S.sectionTitle}>Your Listed Products</div>
                  <div style={S.sectionSub}>{products.length} products · {activeProducts} active</div>
                </div>
                <button style={S.btnPrimary} onClick={() => { setAddError(''); setShowAddModal(true); }}>
                  + Add Product
                </button>
              </div>

              {products.length === 0 ? (
                <div style={S.emptyState}>
                  <div style={{ fontSize: 56, marginBottom: 14 }}>🌾</div>
                  <div style={{ fontSize: 18, fontWeight: 700, color: '#374151', marginBottom: 6 }}>No products listed yet</div>
                  <div style={{ fontSize: 14, color: '#9ca3af' }}>Click "+ Add Product" to list your first item.</div>
                </div>
              ) : (
                <div style={S.productsGrid}>
                  {products.map(p => (
                    <div key={p.id} style={S.productCard}>
                      <div style={S.productImgWrap}>
                        {p.image
                          ? <img src={p.image} alt={p.title} style={S.productImg} onError={e => { e.target.style.display='none'; }} />
                          : <div style={S.productImgPlaceholder}>📦</div>
                        }
                        <span style={{ ...S.productBadge, background: p.status === 'active' ? '#dcfce7' : '#fee2e2', color: p.status === 'active' ? '#16a34a' : '#dc2626' }}>
                          {p.status === 'active' ? '● Live' : '● Paused'}
                        </span>
                      </div>
                      <div style={S.productBody}>
                        <div style={S.productCat}>{p.category}</div>
                        <div style={S.productTitle}>{p.title}</div>
                        <div style={S.productDesc}>{p.desc}</div>
                        <div style={S.productMeta}>
                          <span style={S.metaChip}>📍 {p.location}</span>
                          <span style={S.metaPrice}>₹{p.price}<span style={S.metaUnit}>/kg</span></span>
                        </div>
                        <div style={S.metaStock}>Stock: {p.stock} kg</div>
                        <div style={S.productActions}>
                          <button style={{ ...S.btnSmall, background: '#eff6ff', color: '#3b82f6' }}
                            onClick={() => setEditProduct({ ...p })}>Edit</button>
                          <button style={{ ...S.btnSmall, background: p.status === 'active' ? '#fef3c7' : '#dcfce7', color: p.status === 'active' ? '#d97706' : '#16a34a' }}
                            onClick={() => toggleStatus(p.id)}>
                            {p.status === 'active' ? 'Pause' : 'Activate'}
                          </button>
                          <button style={{ ...S.btnSmall, background: '#fee2e2', color: '#dc2626' }}
                            onClick={() => setDeleteConfirm(p.id)}>Delete</button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}

          {/* ════ BANK DETAILS ════ */}
          {activeTab === 'bank' && (
            <div style={S.formPage}>
              <div style={S.formCard}>
                <div style={S.formCardHeader}>
                  <span style={{ fontSize: 36 }}>🏦</span>
                  <div>
                    <div style={S.formCardTitle}>Bank Account Details</div>
                    <div style={S.formCardSub}>Your payment will be credited here after each fulfilled order.</div>
                  </div>
                </div>

                <div style={S.formGrid}>
                  {[
                    { label: 'Account Holder Name', key: 'accountName',   placeholder: 'As on bank records'       },
                    { label: 'Account Number',       key: 'accountNumber', placeholder: 'Enter account number'     },
                    { label: 'IFSC Code',            key: 'ifsc',          placeholder: 'e.g. SBIN0001234'         },
                    { label: 'Bank Name',            key: 'bankName',      placeholder: 'e.g. State Bank of India' },
                    { label: 'UPI ID (optional)',    key: 'upiId',         placeholder: 'e.g. rajan@upi'          },
                  ].map(f => (
                    <div key={f.key} style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                      <label style={S.formLabel}>{f.label}</label>
                      <input type="text" placeholder={f.placeholder}
                        value={bankDetails[f.key]}
                        onChange={e => setBankDetails(p => ({ ...p, [f.key]: e.target.value }))}
                        style={inputStyle} />
                    </div>
                  ))}
                </div>

                <div style={S.formNotice}>
                  🔒 Your bank details are saved in memory for this session only.
                </div>

                <button
                  style={{ ...S.btnPrimary, width: '100%', padding: 14, fontSize: 15, justifyContent: 'center' }}
                  onClick={handleSaveBank}>
                  {bankSaved ? '✅ Details Saved!' : 'Save Bank Details'}
                </button>
              </div>
            </div>
          )}

          {/* ════ PROFILE ════ */}
          {activeTab === 'profile' && (
            <div style={S.formPage}>
              <div style={S.formCard}>
                <div style={S.profileHero}>
                  <div style={S.profileAvatarLarge}>{avatarInitials}</div>
                  <div>
                    <div style={S.profileName}>{seller.name}</div>
                    <div style={{ fontSize: 13, color: '#16a34a', marginBottom: 4 }}>✅ Verified Seller</div>
                    <div style={{ fontSize: 13, color: '#6b7280' }}>📍 {seller.location}</div>
                  </div>
                </div>

                <div style={{ height: 1, background: '#f3f4f6', margin: '24px 0' }} />

                <div style={S.profileGrid}>
                  {[
                    { icon: '📧', label: 'Email',         value: seller.email    },
                    { icon: '📱', label: 'Phone',         value: seller.phone    },
                    { icon: '📍', label: 'Location',      value: seller.location },
                    { icon: '🪪', label: 'Aadhar Number', value: seller.aadhar   },
                    { icon: '📋', label: 'PAN Number',    value: seller.pan      },
                    { icon: '📅', label: 'Member Since',  value: seller.joined   },
                  ].map((row, i) => (
                    <div key={i} style={S.profileRow}>
                      <div style={{ fontSize: 20 }}>{row.icon}</div>
                      <div>
                        <div style={{ fontSize: 11, color: '#9ca3af', textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 3 }}>{row.label}</div>
                        <div style={{ fontSize: 14, fontWeight: 700, color: '#111827' }}>{row.value}</div>
                      </div>
                    </div>
                  ))}
                </div>

                <div style={S.profileNote}>
                  ℹ️ To update profile details, please contact support.
                </div>
              </div>
            </div>
          )}

        </div>
      </main>

      {/* ══════════ ADD PRODUCT MODAL ══════════ */}
      {showAddModal && (
        <div style={S.overlay} onClick={() => setShowAddModal(false)}>
          <div style={S.modal} onClick={e => e.stopPropagation()}>
            <div style={S.modalHeader}>
              <span style={S.modalTitle}>List New Product</span>
              <button style={S.modalClose} onClick={() => setShowAddModal(false)}>✕</button>
            </div>
            <div style={S.modalBody}>
              {fieldBlock('Product Title *',       'title',    'text',   'e.g. Organic Tomatoes',    newProduct, setNewProduct)}
              {fieldBlock('Description',           'desc',     'text',   'Describe your product...', newProduct, setNewProduct, true)}
              {fieldBlock('Image URL',             'image',    'text',   'https://...',              newProduct, setNewProduct)}
              {fieldBlock('Selling Location *',    'location', 'text',   'e.g. Pune, Maharashtra',  newProduct, setNewProduct)}
              {fieldBlock('Price per kg (₹) *',   'price',    'number', '0.00',                     newProduct, setNewProduct)}
              {fieldBlock('Stock Available (kg)',  'stock',    'number', '0',                        newProduct, setNewProduct)}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                <label style={S.formLabel}>Category</label>
                <select value={newProduct.category} onChange={e => setNewProduct(p => ({ ...p, category: e.target.value }))} style={inputStyle}>
                  {['Vegetables','Fruits','Grains','Dairy','Spices'].map(c => <option key={c}>{c}</option>)}
                </select>
              </div>
              {addError && <div style={S.errBox}>{addError}</div>}
              {newProduct.image && (
                <img src={newProduct.image} alt="preview" style={{ width: '100%', height: 130, objectFit: 'cover', borderRadius: 12 }}
                  onError={e => { e.target.style.display='none'; }} />
              )}
            </div>
            <div style={S.modalFooter}>
              <button style={S.btnGhost} onClick={() => setShowAddModal(false)}>Cancel</button>
              <button style={S.btnPrimary} onClick={handleAddProduct}>List Product</button>
            </div>
          </div>
        </div>
      )}

      {/* ══════════ EDIT PRODUCT MODAL ══════════ */}
      {editProduct && (
        <div style={S.overlay} onClick={() => setEditProduct(null)}>
          <div style={S.modal} onClick={e => e.stopPropagation()}>
            <div style={S.modalHeader}>
              <span style={S.modalTitle}>Edit Product</span>
              <button style={S.modalClose} onClick={() => setEditProduct(null)}>✕</button>
            </div>
            <div style={S.modalBody}>
              {fieldBlock('Product Title *',      'title',    'text',   '', editProduct, setEditProduct)}
              {fieldBlock('Description',          'desc',     'text',   '', editProduct, setEditProduct, true)}
              {fieldBlock('Image URL',            'image',    'text',   '', editProduct, setEditProduct)}
              {fieldBlock('Selling Location *',   'location', 'text',   '', editProduct, setEditProduct)}
              {fieldBlock('Price per kg (₹) *',  'price',    'number', '', editProduct, setEditProduct)}
              {fieldBlock('Stock Available (kg)', 'stock',    'number', '', editProduct, setEditProduct)}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                <label style={S.formLabel}>Category</label>
                <select value={editProduct.category} onChange={e => setEditProduct(p => ({ ...p, category: e.target.value }))} style={inputStyle}>
                  {['Vegetables','Fruits','Grains','Dairy','Spices'].map(c => <option key={c}>{c}</option>)}
                </select>
              </div>
              {editProduct.image && (
                <img src={editProduct.image} alt="preview" style={{ width: '100%', height: 130, objectFit: 'cover', borderRadius: 12 }}
                  onError={e => { e.target.style.display='none'; }} />
              )}
            </div>
            <div style={S.modalFooter}>
              <button style={S.btnGhost} onClick={() => setEditProduct(null)}>Cancel</button>
              <button style={S.btnPrimary} onClick={handleUpdateProduct}>Save Changes</button>
            </div>
          </div>
        </div>
      )}

      {/* ══════════ DELETE CONFIRM MODAL ══════════ */}
      {deleteConfirm && (
        <div style={S.overlay}>
          <div style={{ ...S.modal, maxWidth: 380 }}>
            <div style={{ padding: '32px 28px', textAlign: 'center' }}>
              <div style={{ fontSize: 52, marginBottom: 12 }}>🗑️</div>
              <div style={{ fontSize: 17, fontWeight: 700, color: '#111827', marginBottom: 8 }}>Delete this product?</div>
              <div style={{ fontSize: 13, color: '#6b7280', marginBottom: 28 }}>This will permanently remove it from your listings.</div>
              <div style={{ display: 'flex', gap: 10 }}>
                <button style={{ ...S.btnGhost, flex: 1 }} onClick={() => setDeleteConfirm(null)}>Cancel</button>
                <button style={{ ...S.btnPrimary, flex: 1, justifyContent: 'center', background: '#dc2626', boxShadow: 'none' }}
                  onClick={() => handleDeleteProduct(deleteConfirm)}>Yes, Delete</button>
              </div>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

// ─── STYLES ───────────────────────────────────────────────────────────────────
const S = {
  root: { display:'flex', height:'100vh', width:'100vw', fontFamily:"'Nunito','Segoe UI',sans-serif", background:'#f8fafc', overflow:'hidden' },

  sidebar: { width:240, flexShrink:0, background:'linear-gradient(180deg,#14532d 0%,#166534 60%,#15803d 100%)', display:'flex', flexDirection:'column', padding:'0 0 24px', overflowY:'auto', boxShadow:'4px 0 20px rgba(0,0,0,0.15)' },
  sidebarLogo: { padding:'28px 24px 20px', borderBottom:'1px solid rgba(255,255,255,0.1)' },
  logoText:    { color:'white', fontSize:22, fontWeight:800, letterSpacing:1.5, display:'block' },
  logoAccent:  { color:'#86efac' },
  logoSub:     { color:'rgba(255,255,255,0.45)', fontSize:10, textTransform:'uppercase', letterSpacing:1.5, marginTop:2, display:'block' },

  sidebarAvatar: { display:'flex', alignItems:'center', gap:12, padding:'20px 24px', borderBottom:'1px solid rgba(255,255,255,0.1)' },
  avatarCircle:  { width:44, height:44, borderRadius:'50%', background:'rgba(255,255,255,0.2)', border:'2px solid rgba(255,255,255,0.4)', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:800, fontSize:15, flexShrink:0 },
  avatarName:    { color:'white', fontWeight:700, fontSize:14 },
  avatarRole:    { color:'#86efac', fontSize:11, marginTop:2 },

  sidebarNav:    { flex:1, padding:'16px 12px', display:'flex', flexDirection:'column', gap:4 },
  navItem:       { display:'flex', alignItems:'center', gap:10, padding:'11px 14px', borderRadius:12, border:'none', background:'transparent', color:'rgba(255,255,255,0.6)', fontSize:14, fontWeight:600, cursor:'pointer', textAlign:'left', width:'100%' },
  navItemActive: { background:'rgba(255,255,255,0.15)', color:'white', boxShadow:'inset 0 0 0 1px rgba(255,255,255,0.2)' },
  navIcon:       { fontSize:15, width:20, textAlign:'center' },
  navBadge:      { marginLeft:'auto', background:'rgba(255,255,255,0.2)', borderRadius:20, padding:'2px 8px', fontSize:11, color:'white' },

  sidebarFooter: { padding:'16px 24px', borderTop:'1px solid rgba(255,255,255,0.1)' },
  sidebarBadge:  { background:'rgba(134,239,172,0.2)', border:'1px solid rgba(134,239,172,0.4)', borderRadius:20, padding:'5px 12px', color:'#86efac', fontSize:11, fontWeight:700, marginBottom:8, display:'inline-block' },
  sidebarJoined: { color:'rgba(255,255,255,0.35)', fontSize:11 },

  main:        { flex:1, display:'flex', flexDirection:'column', overflow:'hidden' },
  topbar:      { display:'flex', justifyContent:'space-between', alignItems:'center', padding:'18px 32px', background:'white', borderBottom:'1px solid #e5e7eb', boxShadow:'0 1px 4px rgba(0,0,0,0.06)', flexShrink:0 },
  topbarTitle: { fontSize:20, fontWeight:800, color:'#111827' },
  topbarSub:   { fontSize:13, color:'#9ca3af', marginTop:2 },
  topbarRight: { display:'flex', alignItems:'center', gap:16 },
  topbarDate:  { fontSize:13, color:'#6b7280' },
  topbarAvatar:{ width:38, height:38, borderRadius:'50%', background:'linear-gradient(135deg,#22c55e,#15803d)', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:800, fontSize:13 },

  content:  { flex:1, overflowY:'auto', padding:'28px 32px', display:'flex', flexDirection:'column', gap:24 },

  statsGrid: { display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:16 },
  statCard:  { borderRadius:16, padding:'20px 22px', boxShadow:'0 2px 8px rgba(0,0,0,0.06)' },
  statLabel: { fontSize:12, color:'#6b7280', textTransform:'uppercase', letterSpacing:0.8, marginBottom:8 },
  statValue: { fontSize:28, fontWeight:800, marginBottom:4 },
